// Bad: exposed internals
public class BankAccount {
    public double balance; // anyone can set to negative!
}

// Good: encapsulated
public class BankAccount {
    private double balance;

    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Must be positive");
        this.balance += amount;
    }

    public double getBalance() { return balance; }

    // No setBalance() — callers can't bypass business rules
}

interface Shape {
    double area();
}

class Circle implements Shape {
    private final double radius;
    Circle(double r) { this.radius = r; }
    @Override public double area() { return Math.PI * radius * radius; }
}

class Rectangle implements Shape {
    private final double w, h;
    Rectangle(double w, double h) { this.w = w; this.h = h; }
    @Override public double area() { return w * h; }
}

// Polymorphic call — no instanceof, no casting
List<Shape> shapes = List.of(new Circle(5), new Rectangle(3, 4));
shapes.forEach(s -> System.out.println(s.area()));
// 78.53...
// 12.0

// Interface: defines what, not how
interface Printable {
    void print();                          // must implement
    default void printTwice() {            // optional to override
        print(); print();
    }
}

// Abstract class: partial implementation
abstract class Vehicle {
    private final String plate;
    Vehicle(String plate) { this.plate = plate; }  // shared constructor
    abstract int maxSpeed();               // subclasses define this
    String info() { return plate + " @ " + maxSpeed() + "km/h"; } // shared
}

// A class can do both
class Car extends Vehicle implements Printable {
    Car(String p) { super(p); }
    @Override public int maxSpeed() { return 200; }
    @Override public void print() { System.out.println(info()); }
}
